def normalize_statuses_and_seed_history(apps, schema_editor):
    Order = apps.get_model("orders", "Order")
    OrderStatusHistory = apps.get_model("orders", "OrderStatusHistory")
    status_map = {
        "production": "printing",
        "ready": "packaging",
    }
    for order in Order.objects.all():
        new_status = status_map.get(order.status, order.status)
        if new_status != order.status:
            order.status = new_status
            order.save(update_fields=["status"])
        if not OrderStatusHistory.objects.filter(order=order).exists():
            OrderStatusHistory.objects.create(
                order=order,
                previous_status="",
                new_status=order.status,
                note="Historique initialise pendant la Phase 6.",
            )


